class Solution:
    def minimumCost(self, nums):
        import bisect
        srt = sorted(nums)
        n = len(srt)
        median = srt[n // 2]
        prefix = [0] * (n + 1)
        for i, v in enumerate(srt):
            prefix[i + 1] = prefix[i] + v

        def cost(y):
            idx = bisect.bisect_left(srt, y)
            left_sum = prefix[idx]
            left_count = idx
            right_sum = prefix[n] - prefix[idx]
            right_count = n - idx
            return (y * left_count - left_sum) + (right_sum - y * right_count)

        def make_pal(prefix_str, total_len):
            half = prefix_str
            if total_len % 2 == 0:
                pal = half + half[::-1]
            else:
                pal = half + half[:-1][::-1]
            return int(pal)

        s = str(median)
        length = len(s)
        half_len = (length + 1) // 2
        half_num = int(s[:half_len])

        candidates = set()
        for delta in (-1, 0, 1):
            h = half_num + delta
            if h <= 0:
                continue
            hs = str(h)
            if len(hs) != half_len:
                continue
            candidates.add(make_pal(hs, length))

        if length > 1:
            candidates.add(int('9' * (length - 1)))
        if length + 1 <= 9:
            biglen = length + 1
            half_big = (biglen + 1) // 2
            s2 = '1' + '0' * (half_big - 1)
            candidates.add(make_pal(s2, biglen))

        candidates = {c for c in candidates if 1 <= c < 10 ** 9}
        return min(cost(y) for y in candidates)

