var minimumCost = function(nums) {
    const srt = nums.slice().sort((a, b) => a - b);
    const n = srt.length;
    const median = srt[Math.floor(n / 2)];
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefix[i + 1] = prefix[i] + srt[i];

    function bisectLeft(y) {
        let lo = 0, hi = n;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (srt[mid] < y) lo = mid + 1; else hi = mid;
        }
        return lo;
    }

    function cost(y) {
        const idx = bisectLeft(y);
        const leftSum = prefix[idx];
        const leftCount = idx;
        const rightSum = prefix[n] - prefix[idx];
        const rightCount = n - idx;
        return (y * leftCount - leftSum) + (rightSum - y * rightCount);
    }

    function makePal(prefixStr, totalLen) {
        const half = prefixStr;
        const pal = totalLen % 2 === 0
            ? half + half.split('').reverse().join('')
            : half + half.slice(0, -1).split('').reverse().join('');
        return parseInt(pal, 10);
    }

    const s = String(median);
    const length = s.length;
    const halfLen = Math.floor((length + 1) / 2);
    const halfNum = parseInt(s.slice(0, halfLen), 10);

    const candidates = new Set();
    for (const delta of [-1, 0, 1]) {
        const h = halfNum + delta;
        if (h <= 0) continue;
        const hs = String(h);
        if (hs.length !== halfLen) continue;
        candidates.add(makePal(hs, length));
    }

    if (length > 1) candidates.add(parseInt('9'.repeat(length - 1), 10));
    if (length + 1 <= 9) {
        const bigLen = length + 1;
        const halfBig = Math.floor((bigLen + 1) / 2);
        const s2 = '1' + '0'.repeat(halfBig - 1);
        candidates.add(makePal(s2, bigLen));
    }

    let best = null;
    for (const c of candidates) {
        if (c < 1 || c >= 10 ** 9) continue;
        const c2 = cost(c);
        if (best === null || c2 < best) best = c2;
    }
    return best;
};
